const modelo = ($input.first().json.modelo || '').trim();
const telefono = $input.first().json.telefono;

const BASE = 'https://agncorp.com.ar/marcaschinas';

const MAPA = {
  'JAC JS2':                  `${BASE}/jac/jac-s2/jacs2-fl-ficha-tecnica-2025.pdf`,
  'JAC JS4':                  `${BASE}/jac/jac-js4-flagship/jacjs4-ficha-tecnica-2025.pdf`,
  'JAC JS4 Flagship':         `${BASE}/jac/jac-js4-flagship/jacjs4-ficha-tecnica-2025.pdf`,
  'JAC JS4 Luxury':           `${BASE}/jac/jac-js4-luxury/jacjs4-ficha-tecnica-2025.pdf`,
  'JAC JS6 PHEV':             `${BASE}/jac/jac-js6-phev/20251003-jac-js6phev-fichatecnica.pdf`,
  'JAC JS8':                  `${BASE}/jac/jac-js8-pro/jac-js8-pro-ficha-tecnica.pdf`,
  'JAC JS8 Pro':              `${BASE}/jac/jac-js8-pro/jac-js8-pro-ficha-tecnica.pdf`,
  'JAC EV30X':                `${BASE}/jac/ev-30x/20250922-jac-ev30x-fichatecnica.pdf`,
  'JAC T8':                   `${BASE}/jac/jac-t8-intelligent/ficha-membrete-jact8-intelligent.pdf`,
  'JAC T8 Intelligent':       `${BASE}/jac/jac-t8-intelligent/ficha-membrete-jact8-intelligent.pdf`,
  'JAC T9':                   `${BASE}/jac/jac-t9/20250922-jac-t9-fichatecnica.pdf`,
  'Chery Tiggo 4 Pro':        `${BASE}/chery/chery-tiggo-4-pro-luxury/ficha-tecnica-y-folleto-digital-tiggo-4-pro.pdf`,
  'Chery Tiggo 4 Pro Luxury': `${BASE}/chery/chery-tiggo-4-pro-luxury/ficha-tecnica-y-folleto-digital-tiggo-4-pro.pdf`,
  'GAC GS3':                  `${BASE}/gac/gs3-emzoom/gs3-emzoom-1.pdf`,
  'GAC GS3 EMZOOM':           `${BASE}/gac/gs3-emzoom/gs3-emzoom-1.pdf`,
  'GAC EMKOO':                `${BASE}/gac/emkoo/emkoo-1.pdf`,
  'GAC GS8':                  `${BASE}/gac/gs8/gs8-1.pdf`,
  'GAC EMPOWER':              `${BASE}/gac/nuevo-empow/empow.pdf`,
  'GAC AION ES':              `${BASE}/gac/aion-es/aion-es.pdf`
};

const link = MAPA[modelo];

if (!link) {
  return [{ json: {
    success: false,
    error: `No tengo ficha técnica para "${modelo}". Modelos con ficha disponible: ${Object.keys(MAPA).join(', ')}`,
    modelo,
    telefono
  }}];
}

return [{ json: { telefono, modelo, link, success: true }}];
